<?php require_once __DIR__.'/../includes/db.php'; require_login(); page_header(tr('analytics'),'analytics'); $q=trim($_GET['q']??''); $stats=['questions'=>stat_count('hier_questions'),'records'=>stat_count('raw_exam_results'),'topics'=>stat_count('ai_syllabus_topics'),'imports'=>stat_count('imports_log')]; $items=[]; if(table_exists('hier_questions')){ $where='';$params=[]; if($q!==''){ $where='WHERE h.question_text LIKE ? OR st.discipline_name LIKE ? OR st.title LIKE ?'; $params=['%'.$q.'%','%'.$q.'%','%'.$q.'%']; } $items=rows("SELECT h.question_id,h.question_text,st.discipline_name,st.course_number,st.title topic_title,qvc.status,qsc.alignment_level,qsc.avg_score,qsc.student_attempts FROM hier_questions h LEFT JOIN ai_syllabus_topics st ON st.syllabus_topic_id=h.syllabus_topic_id LEFT JOIN question_validation_cache qvc ON qvc.question_id=h.question_id LEFT JOIN question_semantic_cache qsc ON qsc.question_id=h.question_id $where ORDER BY h.question_id DESC LIMIT 250",$params); } ?><div class="hero"><div><div class="hero-kicker">ANALYTICS</div><h2><?=h(tr('analytics'))?></h2><p>Обзор вопросов, результатов, статусов проверки и связей с силлабусом из базы <?=h(cfg('db_name'))?>.</p></div><a class="btn light" href="full_analytics.php?lang=<?=h(current_lang())?>">Расширенная аналитика</a></div><div class="grid"><?php foreach($stats as $k=>$v):?><div class="card"><h3><?=h(tr($k))?></h3><div class="stat"><?=h($v)?></div></div><?php endforeach;?></div><div class="card" style="margin-top:24px"><div class="toolbar"><h2><?=h(tr('search'))?></h2><form method="get"><input type="hidden" name="lang" value="<?=h(current_lang())?>"><input class="input" name="q" value="<?=h($q)?>" placeholder="<?=h(tr('search_placeholder'))?>"><button class="btn"><?=h(tr('search'))?></button></form></div><div class="table-wrap"><table class="table"><thead><tr><th>ID</th><th><?=h(tr('text'))?></th><th><?=h(tr('discipline'))?></th><th><?=h(tr('topics'))?></th><th><?=h(tr('status'))?></th><th>Alignment</th><th>Avg</th></tr></thead><tbody><?php foreach($items as $r):?><tr><td><?=h($r['question_id'])?></td><td><?=h($r['question_text'])?></td><td><?=h($r['discipline_name']??'')?></td><td><?=h($r['topic_title']??'')?></td><td><span class="pill"><?=h($r['status']??'')?></span></td><td><?=h($r['alignment_level']??'')?></td><td><?=h($r['avg_score']??'')?></td></tr><?php endforeach;?><?php if(!$items):?><tr><td colspan="7" class="empty"><?=h(tr('no_data'))?></td></tr><?php endif;?></tbody></table></div></div><?php page_footer(); ?>